    console.log(`Saltando item inválido: ${JSON.stringify(item).slice(0, 100)}`);
    return false;
  }
  return true;
});

console.log(`Items válidos: ${valid.length}/${body.items.length}`);
return valid.map(item => ({ json: item }));

