// Construir JWT con Node.js crypto (RS256)
const now = Math.floor(Date.now() / 1000);
const jwtHeader  = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
const jwtPayload = Buffer.from(JSON.stringify({
  iss: SA_EMAIL,
  scope: 'https://www.googleapis.com/auth/cloud-platform',
  aud: 'https://oauth2.googleapis.com/token',
  exp: now + 3600,
  iat: now
})).toString('base64url');

const signingInput = `${jwtHeader}.${jwtPayload}`;
const sign = crypto.createSign('RSA-SHA256');
sign.update(signingInput);
const signature = sign.sign(SA_KEY, 'base64url');
const jwt = `${signingInput}.${signature}`;

// Obtener access token de Google
const tokenRes = await $http.request({
  method: 'POST',
  url: 'https://oauth2.googleapis.com/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: `grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=${jwt}`
});

const accessToken = tokenRes.access_token;
if (!accessToken) throw new Error('No se pudo obtener access token: ' + JSON.stringify(tokenRes));

// Llamar a Vertex AI text-embedding-004
const textToEmbed = `${item.title}\n\n${item.content}`.slice(0, 2000);

const vertexRes = await $http.request({
  method: 'POST',
  url: `https://us-central1-aiplatform.googleapis.com/v1/projects/${PROJECT}/locations/us-central1/publishers/google/models/text-embedding-004:predict`,
  headers: {
    'Authorization': `Bearer ${accessToken}`,
    'Content-Type': 'application/json'
  },
  body: {
    instances: [{ task_type: 'RETRIEVAL_DOCUMENT', content: textToEmbed }]
  }
});

const embedding = vertexRes.predictions?.[0]?.embeddings?.values;
if (!embedding || !Array.isArray(embedding)) {
  throw new Error(`Embedding inválido para "${item.id}": ${JSON.stringify(vertexRes).slice(0, 300)}`);
}

console.log(`✓ "${item.id}": ${embedding.length} dims`);

return { json: {
  id: item.id, category: item.category, title: item.title,
  content: item.content, is_active: item.is_active,
  embedding: JSON.stringify(embedding)
} };

